ord in isolation.', NULL, 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"hard_content_v2","original":true,"explanation_v2":true,"hard_content_v2":true}'::jsonb, now(), now())
